const body = $json.body || $json;

const customer_name = body.name || body.customer_name;
const email = body.email;
const service = body.service;
const appointment_time = body.time || body.appointment_time;

if (!customer_name || !email || !service || !appointment_time) {
  throw new Error('Missing required fields. Required: name/email/service/time');
}

const token = `${Date.now()}_${Math.random().toString(36).slice(2)}_${Math.random().toString(36).slice(2)}`;

const baseUrl = body.public_base_url || 'http://localhost:5678/webhook';
const confirm_link = `${baseUrl}/systack-confirm?token=${encodeURIComponent(token)}`;

function sqlSafe(value) {
  return String(value).replace(/'/g, "''");
}

return [
  {
    json: {
      customer_name,
      email,
      service,
      appointment_time,
      confirmation_token: token,
      confirm_link,
      sql_customer_name: sqlSafe(customer_name),
      sql_email: sqlSafe(email),
      sql_service: sqlSafe(service),
      sql_appointment_time: sqlSafe(appointment_time),
      sql_confirmation_token: sqlSafe(token)
    }
  }
];

const original = $('Prepare Booking + Token').first().json;
const inserted = $json;

return [
  {
    json: {
      ...original,
      booking_id: inserted.id,
      status: inserted.status,
      confirmed: inserted.confirmed
    }
  }
];

const query = $json.query || {};
const token = query.token;

if (!token) {
  throw new Error('Missing confirmation token.');
}

function sqlSafe(value) {
  return String(value).replace(/'/g, "''");
}

return [
  {
    json: {
      confirmation_token: token,
      sql_confirmation_token: sqlSafe(token)
    }
  }
];

if (!$json.id) {
  return [
    {
      json: {
        success: false,
        html: '<h2>Invalid or expired confirmation link.</h2><p>Please contact the business directly.</p>'
      }
    }
  ];
}

return [
  {
    json: {
      success: true,
      booking_id: $json.id,
      customer_name: $json.customer_name,
      email: $json.email,
      service: $json.service,
      appointment_time: $json.appointment_time,
      status: $json.status,
      confirmed: $json.confirmed,
      html: `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 40px auto; color: #111;">
        <h2>Appointment confirmed ✅</h2>
        <p>Thank you, <strong>${$json.customer_name}</strong>.</p>
        <p>Your appointment is confirmed.</p>
        <ul>
          <li><strong>Service:</strong> ${$json.service}</li>
          <li><strong>Time:</strong> ${$json.appointment_time}</li>
        </ul>
      </div>`
    }
  }
];
